import { pipe } from 'fp-ts/function';

const ensureNonEmpty = (s: string): string => {
  if (s.length === 0) throw new Error('empty');
  return s;
};
const normalise = (s: string): string => s.normalize('NFC').toLowerCase();
const dropSpaces = (s: string): string => s.replace(/\s+/g, '');
const djb2 = (s: string): number => {
  let h = 5381;
  for (const ch of s) h = (h * 33) ^ ch.charCodeAt(0);
  return h >>> 0;
};

export const quickHash = (raw: string): number =>
  pipe(raw, ensureNonEmpty, normalise, dropSpaces, djb2);
```

Each step has exactly one responsibility and reads top-to-bottom — the pipeline literally documents the business rule.

```ts
import { pipe } from 'fp-ts/function';
import * as A from 'fp-ts/ReadonlyArray';

const isEven = (n: number): boolean => n % 2 === 0;
const times10 = (n: number): number => n * 10;
const sum = (xs: ReadonlyArray<number>): number => xs.reduce((a, b) => a + b, 0);

export const out: number = pipe(
  [1, 2, 3, 4] as ReadonlyArray<number>,
  A.filter(isEven),
  A.map(times10),
  sum
);
```

The `fp-ts` array combinators are data-last, so `pipe` is how you feed the array through them. Native `Array.prototype` is fine for quick work, but `pipe` + `ReadonlyArray` gives you immutability and consistent ordering with the rest of an fp-ts codebase.

```ts
import { pipe } from 'fp-ts/function';
import * as A from 'fp-ts/ReadonlyArray';

const split = (sep: string) => (s: string): ReadonlyArray<string> => s.split(sep);
const trimAll = A.map((s: string) => s.trim());
const dropEmpty = A.filter((s: string) => s.length > 0);
const toNumbers = A.map((s: string) => Number(s));

export const parseRow = (row: string): ReadonlyArray<number> =>
  pipe(row, split(','), trimAll, dropEmpty, toNumbers);
